import React, { useState } from 'react';
import { X } from 'lucide-react';
import './AnnouncementForm.css';

/**
 * AnnouncementForm Component
 * Provides form for admins to create and edit announcements
 */
export function AnnouncementForm({ onSubmit, onCancel, initialData = null, isLoading = false }) {
  const [formData, setFormData] = useState(initialData || {
    title: '',
    description: '',
    audience: 'All',
    priority: 'Normal',
    publishDate: new Date().toISOString().split('T')[0],
    expiryDate: '',
    isPinned: false,
    isPublished: true
  });

  const [errors, setErrors] = useState({});

  const validateForm = () => {
    const newErrors = {};
    if (!formData.title.trim()) newErrors.title = 'Title is required';
    if (!formData.description.trim()) newErrors.description = 'Description is required';
    if (formData.expiryDate && formData.publishDate > formData.expiryDate) {
      newErrors.expiryDate = 'Expiry date must be after publish date';
    }
    return newErrors;
  };

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const newErrors = validateForm();

    if (Object.keys(newErrors).length === 0) {
      onSubmit(formData);
    } else {
      setErrors(newErrors);
    }
  };

  return (
    <div className="announcement-form-overlay">
      <div className="announcement-form-container">
        <div className="announcement-form-header">
          <h2>{initialData ? 'Edit Announcement' : 'Create Announcement'}</h2>
          <button
            type="button"
            onClick={onCancel}
            className="close-btn"
            disabled={isLoading}
          >
            <X className="icon" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="announcement-form">
          {/* Title Field */}
          <div className="form-group">
            <label htmlFor="title">
              Title *
              {errors.title && <span className="error-text">{errors.title}</span>}
            </label>
            <input
              id="title"
              type="text"
              name="title"
              value={formData.title}
              onChange={handleInputChange}
              placeholder="Enter announcement title"
              maxLength="200"
              className={errors.title ? 'input-error' : ''}
              disabled={isLoading}
            />
            <small className="char-count">{formData.title.length}/200</small>
          </div>

          {/* Description Field */}
          <div className="form-group">
            <label htmlFor="description">
              Description *
              {errors.description && <span className="error-text">{errors.description}</span>}
            </label>
            <textarea
              id="description"
              name="description"
              value={formData.description}
              onChange={handleInputChange}
              placeholder="Enter detailed announcement description"
              maxLength="5000"
              rows="6"
              className={errors.description ? 'textarea-error' : ''}
              disabled={isLoading}
            />
            <small className="char-count">{formData.description.length}/5000</small>
          </div>

          {/* Two Column Section */}
          <div className="form-row">
            {/* Audience Field */}
            <div className="form-group">
              <label htmlFor="audience">Audience</label>
              <select
                id="audience"
                name="audience"
                value={formData.audience}
                onChange={handleInputChange}
                disabled={isLoading}
              >
                <option value="All">All Users</option>
                <option value="Students">Students Only</option>
                <option value="Teachers">Teachers Only</option>
                <option value="Parents">Parents Only</option>
                <option value="Staff">Staff Only</option>
              </select>
            </div>

            {/* Priority Field */}
            <div className="form-group">
              <label htmlFor="priority">Priority</label>
              <select
                id="priority"
                name="priority"
                value={formData.priority}
                onChange={handleInputChange}
                disabled={isLoading}
              >
                <option value="Low">Low</option>
                <option value="Normal">Normal</option>
                <option value="Important">Important</option>
                <option value="Urgent">Urgent</option>
              </select>
            </div>
          </div>

          {/* Date Fields */}
          <div className="form-row">
            {/* Publish Date */}
            <div className="form-group">
              <label htmlFor="publishDate">Publish Date</label>
              <input
                id="publishDate"
                type="date"
                name="publishDate"
                value={formData.publishDate}
                onChange={handleInputChange}
                disabled={isLoading}
              />
            </div>

            {/* Expiry Date */}
            <div className="form-group">
              <label htmlFor="expiryDate">
                Expiry Date
                {errors.expiryDate && <span className="error-text">{errors.expiryDate}</span>}
              </label>
              <input
                id="expiryDate"
                type="date"
                name="expiryDate"
                value={formData.expiryDate}
                onChange={handleInputChange}
                className={errors.expiryDate ? 'input-error' : ''}
                disabled={isLoading}
              />
            </div>
          </div>

          {/* Checkbox Fields */}
          <div className="form-checkboxes">
            <label className="checkbox-label">
              <input
                type="checkbox"
                name="isPinned"
                checked={formData.isPinned}
                onChange={handleInputChange}
                disabled={isLoading}
              />
              <span>Pin this announcement to the top</span>
            </label>
            <label className="checkbox-label">
              <input
                type="checkbox"
                name="isPublished"
                checked={formData.isPublished}
                onChange={handleInputChange}
                disabled={isLoading}
              />
              <span>Publish immediately</span>
            </label>
          </div>

          {/* Form Actions */}
          <div className="form-actions">
            <button
              type="button"
              onClick={onCancel}
              className="btn-cancel"
              disabled={isLoading}
            >
              Cancel
            </button>
            <button
              type="submit"
              className="btn-submit"
              disabled={isLoading}
            >
              {isLoading ? 'Saving...' : (initialData ? 'Update Announcement' : 'Create Announcement')}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
